import logo from '../assets/images/logo.png';
import { Link } from "react-router-dom";
function Nav() {
    return (
        <>
            <div>
                <img src={logo} alt="logo" />
            <nav>
                <Link to='/'>Home</Link>
                <Link to='/about'>About</Link>
            </nav>
            </div>
        </>
    )
}
export default Nav;
